#!/usr/bin/env node

// Publishes a public preview of the bundle in the current directory: collects
// twilight-bundle.json, templates/*.json and the built dist/*.js each template references,
// uploads them as a snapshot to the preview Worker (packages/public-preview-worker in the
// twilight-bundles repo), and prints the shareable URL. No npm publish and no public GitHub
// repo needed — the snapshot itself is what gets served.
//
// The returned snapshot id + write key are saved to .salla-preview.json next to
// twilight-bundle.json, so re-running after changes updates the same preview URL in place.
//
// Usage: tw-preview
// Env:   TW_PREVIEW_BASE_URL  — Worker origin (default https://salla.design)
//        TW_PREVIEW_TOKEN     — optional explicit upload token (CI); interactive use needs no
//                               env at all — the Salla CLI's stored login (`salla login`,
//                               ~/.salla/config.json) authorizes the first publish.

import crypto from 'crypto';
import fs from 'fs';
import os from 'os';
import path from 'path';

const baseUrl = (process.env.TW_PREVIEW_BASE_URL || 'https://salla.design').replace(/\/$/, '');
const apiUrl = `${baseUrl}/preview/api/snapshots`;

const projectRoot = process.cwd();
const stateFile = path.join(projectRoot, '.salla-preview.json');

function fail(message) {
  console.error(`❌ ${message}`);
  process.exit(1);
}

// Top-level twilight-bundle.json flag (set via the demo's "Is landing Template?" toggle,
// bundle-settings panel) opting a bundle into Salla's landing-page-templates surface — which
// only makes sense with more than one template. Duplicated from server-side/index.ts's same
// constants (this bin script can't import from src/); the Worker (snapshots.ts) re-checks the
// same range server-side against whatever bundleJson the payload actually carries, since a
// hand-crafted upload could skip this client-side gate entirely.
const LANDING_FEATURE = 'landing-page-templates';
const LANDING_MIN_TEMPLATES = 2;
const LANDING_MAX_TEMPLATES = 4;
const DEFAULT_MIN_TEMPLATES = 1;

function validateTemplateCount(bundleJson, templateCount) {
  const isLanding = Array.isArray(bundleJson.features) && bundleJson.features.includes(LANDING_FEATURE);
  const min = isLanding ? LANDING_MIN_TEMPLATES : DEFAULT_MIN_TEMPLATES;

  if (templateCount < min) {
    if (isLanding) {
      fail(`This bundle has "${LANDING_FEATURE}" enabled, which needs at least ${min} templates to publish (found ${templateCount}). Save more templates from the demo (pnpm dev) first.`);
    } else {
      fail('No templates found — save at least one template from the demo (pnpm dev) first.');
    }
  }
  if (templateCount > LANDING_MAX_TEMPLATES) {
    fail(`Too many templates to publish (${templateCount}) — the maximum is ${LANDING_MAX_TEMPLATES}. Delete extra templates first.`);
  }
}

function collectPayload() {
  const bundleJsonPath = path.join(projectRoot, 'twilight-bundle.json');
  if (!fs.existsSync(bundleJsonPath)) {
    fail('twilight-bundle.json not found — run tw-preview from the bundle root.');
  }
  const bundleJson = JSON.parse(fs.readFileSync(bundleJsonPath, 'utf8'));

  const templatesDir = path.join(projectRoot, 'templates');
  const templateNames = fs.existsSync(templatesDir)
    ? fs.readdirSync(templatesDir).filter(f => f.endsWith('.json')).map(f => f.replace(/\.json$/, ''))
    : [];
  validateTemplateCount(bundleJson, templateNames.length);

  const templates = {};
  const componentNames = new Set();
  for (const name of templateNames) {
    const template = JSON.parse(fs.readFileSync(path.join(templatesDir, `${name}.json`), 'utf8'));
    templates[name] = template;
    for (const component of template.components || []) {
      componentNames.add(component.name);
    }
  }

  // Upload every top-level dist/*.js, not just the template-referenced components: Vite
  // code-splits shared modules into sibling chunk files (e.g. scroll-scene-DdINwXtt.js) that
  // component modules import relatively, so the served preview needs all of them.
  const distDir = path.join(projectRoot, 'dist');
  const dist = {};
  if (fs.existsSync(distDir)) {
    for (const file of fs.readdirSync(distDir)) {
      if (file.endsWith('.js') && fs.statSync(path.join(distDir, file)).isFile()) {
        dist[file.replace(/\.js$/, '')] = fs.readFileSync(path.join(distDir, file), 'utf8');
      }
    }
  }
  for (const name of componentNames) {
    if (dist[name] === undefined) {
      fail(`Template(s) reference component "${name}" but dist/${name}.js is missing — run "pnpm build" first.`);
    }
  }

  const packageName = fs.existsSync(path.join(projectRoot, 'package.json'))
    ? (JSON.parse(fs.readFileSync(path.join(projectRoot, 'package.json'), 'utf8')).name || 'bundle')
    : 'bundle';
  // Snapshot names share the template-name charset — strip an npm scope and anything else outside it.
  const name = packageName.replace(/^@[^/]+\//, '').toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/^-+|-+$/g, '') || 'bundle';

  return { name, bundleJson, templates, dist };
}

// Media under dist/assets/ (images, fonts, video the bundle references as "/assets/…") — each
// file is uploaded as its own object after the snapshot itself, and the Worker rewrites the
// bundle's root-absolute /assets/ references to the snapshot's own asset URLs at store time.
// Charset must mirror the Worker's isValidAssetPath: the stored key has to be byte-identical
// to the URL path a browser will later request.
const ASSET_SEGMENT_PATTERN = /^[A-Za-z0-9_+-][A-Za-z0-9._+-]*$/;
const MAX_ASSET_BYTES = 50 * 1024 * 1024;

const ASSET_CONTENT_TYPES = {
  '.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.gif': 'image/gif',
  '.svg': 'image/svg+xml', '.webp': 'image/webp', '.avif': 'image/avif', '.ico': 'image/x-icon',
  '.mp4': 'video/mp4', '.webm': 'video/webm', '.mp3': 'audio/mpeg', '.wav': 'audio/wav',
  '.otf': 'font/otf', '.ttf': 'font/ttf', '.woff': 'font/woff', '.woff2': 'font/woff2',
  '.css': 'text/css', '.js': 'application/javascript', '.json': 'application/json',
};

function collectAssets() {
  const assetsDir = path.join(projectRoot, 'dist', 'assets');
  if (!fs.existsSync(assetsDir)) return [];

  const assets = [];
  const walk = (dir, prefix) => {
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      const relPath = prefix ? `${prefix}/${entry.name}` : entry.name;
      if (!ASSET_SEGMENT_PATTERN.test(entry.name)) {
        console.warn(`⚠️ Skipping asset with unsupported filename: assets/${relPath} (rename to letters/digits/._+- only)`);
        continue;
      }
      if (entry.isDirectory()) {
        walk(path.join(dir, entry.name), relPath);
      } else if (entry.isFile()) {
        const size = fs.statSync(path.join(dir, entry.name)).size;
        if (size > MAX_ASSET_BYTES) {
          console.warn(`⚠️ Skipping assets/${relPath} — ${(size / 1024 / 1024).toFixed(1)}MB exceeds the ${MAX_ASSET_BYTES / 1024 / 1024}MB per-file limit`);
          continue;
        }
        assets.push({ relPath, fullPath: path.join(dir, entry.name), size });
      }
    }
  };
  walk(assetsDir, '');
  return assets;
}

// One media PUT with retries: large uploads over residential connections hit transient
// network resets, and a single blip shouldn't abort the whole publish. Client errors (4xx)
// won't change on retry, so only network failures and 5xx are retried.
async function uploadOneAsset(id, writeKey, asset, attempts = 3) {
  const contentType = ASSET_CONTENT_TYPES[path.extname(asset.relPath).toLowerCase()] || 'application/octet-stream';
  for (let attempt = 1; attempt <= attempts; attempt++) {
    let response;
    try {
      response = await fetch(`${apiUrl}/${id}/assets/${asset.relPath}`, {
        method: 'PUT',
        headers: { 'Content-Type': contentType, 'X-Write-Key': writeKey },
        body: fs.readFileSync(asset.fullPath),
      });
    } catch (error) {
      if (attempt === attempts) fail(`Asset upload failed for assets/${asset.relPath}: ${error.cause?.message || error.message}`);
      console.warn(`⚠️ assets/${asset.relPath}: ${error.cause?.message || error.message} — retrying (${attempt}/${attempts - 1})`);
      await new Promise(resolve => setTimeout(resolve, attempt * 1000));
      continue;
    }
    if (response.ok) return;
    let body;
    try { body = await response.json(); } catch { body = {}; }
    if (response.status < 500 || attempt === attempts) {
      fail(`Asset upload failed for assets/${asset.relPath} (${response.status}): ${body.error || 'unknown error'}`);
    }
    console.warn(`⚠️ assets/${asset.relPath}: HTTP ${response.status} — retrying (${attempt}/${attempts - 1})`);
    await new Promise(resolve => setTimeout(resolve, attempt * 1000));
  }
}

// {path: sha256} of what the Worker already stores for this snapshot — so unchanged files are
// skipped instead of re-sent on every publish. Null (e.g. against an older Worker without the
// manifest endpoint) means "unknown": upload everything, delete nothing.
async function fetchAssetManifest(id, writeKey) {
  try {
    const response = await fetch(`${apiUrl}/${id}/assets`, { headers: { 'X-Write-Key': writeKey } });
    if (!response.ok) return null;
    return (await response.json()).assets || {};
  } catch {
    return null;
  }
}

// {relPath: sha256} of the local dist/assets files. Sent with the snapshot metadata (the
// Worker turns them into per-file ?v=<hash> cache-busters on every rewritten reference) and
// reused for the incremental diff against the Worker's stored manifest.
function hashLocalAssets(assets) {
  const hashes = {};
  for (const asset of assets) {
    hashes[asset.relPath] = crypto.createHash('sha256').update(fs.readFileSync(asset.fullPath)).digest('hex');
  }
  return hashes;
}

async function uploadAssets(id, writeKey, assets, localHashes) {
  const remote = await fetchAssetManifest(id, writeKey);

  const changed = assets.filter(asset => {
    if (remote === null) return true;
    return remote[asset.relPath] !== localHashes[asset.relPath];
  });

  const removed = remote === null ? [] : Object.keys(remote).filter(remotePath => !assets.some(a => a.relPath === remotePath));

  if (changed.length === 0 && removed.length === 0) {
    if (assets.length > 0) console.log(`🖼  Assets unchanged (${assets.length} file(s) already up to date).`);
    return;
  }

  if (changed.length > 0) {
    const totalMb = changed.reduce((sum, a) => sum + a.size, 0) / 1024 / 1024;
    const skipped = assets.length - changed.length;
    console.log(`🖼  Uploading ${changed.length} asset file(s) (${totalMb.toFixed(1)}MB)${skipped > 0 ? `, ${skipped} unchanged` : ''} ...`);
  }

  for (const asset of changed) {
    await uploadOneAsset(id, writeKey, asset);
  }

  for (const relPath of removed) {
    await fetch(`${apiUrl}/${id}/assets/${relPath}`, { method: 'DELETE', headers: { 'X-Write-Key': writeKey } });
  }
  if (removed.length > 0) console.log(`🧹 Removed ${removed.length} asset file(s) no longer in dist/assets.`);
}

// Persists each template's shareable page URL into its own registry entry in
// twilight-bundle.json (public_preview_url) — so the link lives next to the template
// registration instead of only scrolling by in terminal output. Idempotent: the file is only
// rewritten when a URL is new or changed.
function saveManifestPreviewUrls(payload, id) {
  const manifestPath = path.join(projectRoot, 'twilight-bundle.json');
  const raw = fs.readFileSync(manifestPath, 'utf8');
  const manifest = JSON.parse(raw);

  let changed = 0;
  for (const entry of manifest.templates || []) {
    const templateName = (entry.path || '').replace(/^templates\./, '');
    if (!templateName || !payload.templates[templateName]) continue;
    const url = `${baseUrl}/preview/s/${id}/${templateName}`;
    if (entry.public_preview_url !== url) {
      entry.public_preview_url = url;
      changed++;
    }
  }
  if (changed === 0) return;

  // Match the file's existing top-level indentation (the demo dev server and tw-init both
  // rewrite this file too — don't churn the whole diff over whitespace).
  const indent = (raw.split('\n')[1] || '').match(/^(\s*)/)[1].length || 2;
  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, indent) + (raw.endsWith('\n') ? '\n' : ''));
  console.log(`🔗 Saved public_preview_url for ${changed} template(s) in twilight-bundle.json`);
}

// First publish only (updates use the saved write key): an explicit TW_PREVIEW_TOKEN wins,
// otherwise fall back to the partner access token the Salla CLI stores after `salla login` —
// the preview Worker accepts either.
function resolveUploadToken() {
  if (process.env.TW_PREVIEW_TOKEN) return process.env.TW_PREVIEW_TOKEN;
  try {
    const cliConfig = JSON.parse(fs.readFileSync(path.join(os.homedir(), '.salla', 'config.json'), 'utf8'));
    return cliConfig?.salla?.access_token || null;
  } catch {
    return null;
  }
}

function readState() {
  try {
    return JSON.parse(fs.readFileSync(stateFile, 'utf8'));
  } catch {
    return null;
  }
}

// The write key is the update capability for the preview URL — make sure the state file never
// lands in the bundle's repo by default (scaffolded bundles ship without a .gitignore).
function ensureGitignored(entry) {
  const gitignorePath = path.join(projectRoot, '.gitignore');
  const current = fs.existsSync(gitignorePath) ? fs.readFileSync(gitignorePath, 'utf8') : '';
  if (current.split('\n').some(line => line.trim() === entry)) return;
  fs.writeFileSync(gitignorePath, current ? `${current.replace(/\n?$/, '\n')}${entry}\n` : `${entry}\n`);
}

async function publish() {
  const payload = collectPayload();
  const assets = collectAssets();
  const localHashes = hashLocalAssets(assets);
  // Hashes ride along with the metadata so the Worker can version every rewritten asset
  // reference per file (?v=<hash>) — CDN-cacheable forever, fresh URL only when a file changes.
  payload.assetHashes = localHashes;
  const scriptCount = Object.keys(payload.dist).length;
  const templateCount = Object.keys(payload.templates).length;
  console.log(`📦 Publishing preview: ${templateCount} template(s), ${scriptCount} script(s)`);

  const state = readState();

  let response;
  if (state?.id && state?.writeKey) {
    console.log(`🔁 Updating existing preview ${state.id} ...`);
    response = await fetch(`${apiUrl}/${state.id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json', 'X-Write-Key': state.writeKey },
      body: JSON.stringify(payload),
    });
    // A deleted/expired snapshot comes back 404 — fall through to creating a fresh one.
    if (response.status === 404) {
      console.log('⚠️ Previous preview no longer exists, creating a new one ...');
      response = null;
    }
  }

  if (!response) {
    const token = resolveUploadToken();
    if (!token) {
      fail('Not logged in. Run "salla login" first (or set TW_PREVIEW_TOKEN) and re-run.');
    }
    response = await fetch(apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify(payload),
    });
  }

  let body;
  try {
    body = await response.json();
  } catch {
    body = {};
  }

  if (!response.ok) {
    fail(`Upload failed (${response.status}): ${body.error || 'unknown error'}`);
  }

  if (body.writeKey) {
    fs.writeFileSync(stateFile, JSON.stringify({ id: body.id, writeKey: body.writeKey }, null, 2));
    ensureGitignored(path.basename(stateFile));
    console.log(`🔑 Saved preview credentials to ${path.basename(stateFile)} — keep it out of public repos.`);
  }

  const id = body.id || state?.id;
  const writeKey = body.writeKey || state?.writeKey;
  if (id && writeKey) {
    await uploadAssets(id, writeKey, assets, localHashes);
  }
  if (id) {
    saveManifestPreviewUrls(payload, id);
  }

  // Prefer rebuilding from our own base URL: behind `wrangler dev` the Worker sees the
  // production route host in request.url, so its absolute `url` can point at the wrong origin.
  const url = body.path ? `${baseUrl}${body.path}` : body.url;
  console.log('\n✅ Public preview is live:');
  console.log(`   ${url}\n`);
}

publish().catch(error => fail(error.message));
